	detail := strings.Join(skipReasons, "\n")
	if detail == "" {
		detail = "no viable harness found"
	}
	_ = beadStore.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "tier-attempt",
		Summary:   "skipped",
		Body:      escalation.FormatTierAttemptBody(string(tier), "", "", probeResult, detail),
		Actor:     "ddx",
